import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { AuthService } from './core/services/auth.service';
import { UserDTO } from './core/models/user.model';

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.scss']
})
export class AppComponent implements OnInit {
  title = 'HackHub';
  isMobileMenuOpen = false;
  currentUser: UserDTO | null = null;

  constructor(
    private authService: AuthService,
    private router: Router
  ) {}

  ngOnInit(): void {
    this.authService.currentUser$.subscribe(user => {
      this.currentUser = user;
    });
  }

  toggleMobileMenu(): void {
    this.isMobileMenuOpen = !this.isMobileMenuOpen;
  }

  logout(): void {
    this.authService.logout().subscribe({
      next: () => {
        // Successo backend
        this.authService.clearAuth();
        this.router.navigate(['/auth/login']);
        this.isMobileMenuOpen = false;
      },
      error: (error) => {
        // Errore backend (500, 403, etc.) - comunque pulisci i dati locali
        console.warn('Backend logout failed, clearing local auth:', error);
        this.authService.clearAuth();
        this.router.navigate(['/auth/login']);
        this.isMobileMenuOpen = false;
      },
      complete: () => {
        // Questo viene chiamato solo in caso di successo
        console.log('Logout completed successfully');
      }
    });
  }
}
<div class="app-container">
  <!-- Sidebar -->
  <aside class="sidebar" [class.mobile-open]="isMobileMenuOpen">
    <a routerLink="/dashboard" class="logo">
      <span>🚀</span>
      <span>HackHub</span>
    </a>

    <nav class="nav-menu">
      <a routerLink="/dashboard" class="nav-item" routerLinkActive="active">
        <span>📊</span>
        <span>Dashboard</span>
      </a>
      <a routerLink="/hackathons" class="nav-item" routerLinkActive="active">
        <span>🏆</span>
        <span>Hackathons</span>
      </a>
      <a routerLink="/teams" class="nav-item" routerLinkActive="active">
        <span>👥</span>
        <span>Teams</span>
      </a>
      <a routerLink="/profile" class="nav-item" routerLinkActive="active">
        <span>👤</span>
        <span>Profile</span>
      </a>
    </nav>
  </aside>

  <!-- Mobile Overlay -->
  <div class="mobile-overlay" [class.hidden]="!isMobileMenuOpen" (click)="toggleMobileMenu()"></div>

  <!-- Main Content -->
  <div class="main-content">
    <!-- Topbar -->
    <header class="topbar">
      <button class="mobile-menu-toggle" (click)="toggleMobileMenu()">
        ☰
      </button>

      <div class="user-info">
        <div class="user-details">
          <div class="user-name">{{ currentUser?.nome }} {{ currentUser?.cognome }}</div>
          <div class="user-role">{{ currentUser?.ruolo }}</div>
        </div>
        <div class="user-avatar">{{ currentUser?.nome?.charAt(0) }}{{ currentUser?.cognome?.charAt(0) }}</div>
        <button class="logout-btn" (click)="logout()">
          <span>🚪</span>
          <span>Logout</span>
        </button>
      </div>
    </header>

    <!-- Page Content -->
    <main class="page-content">
      <router-outlet></router-outlet>
    </main>
  </div>
</div>
